// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
long long dp[100005][55];
long long modPow(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}
long long inv(long long a) {
    return modPow(a, MOD - 2);
}
int main() {
    int N, K, a, b;
    scanf("%d %d %d %d", &N, &K, &a, &b);
    for (int i = 0; i <= N; i++) {
        for (int j = 0; j <= K; j++) {
            dp[i][j] = 0;
        }
    }
    dp[0][K / 2] = 1;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j <= K; j++) {
            if (j > 0) dp[i + 1][j - 1] = (dp[i + 1][j - 1] + dp[i][j]) % MOD;
            dp[i + 1][j] = (dp[i + 1][j] + dp[i][j] * 2) % MOD;
            if (j < K) dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD;
        }
    }
    long long totalPaths = dp[N][K / 2];
    long long blockedPaths = 0;
    for (int i = 2; i < N; i++) {
        blockedPaths = (blockedPaths + dp[i - 1][a] * dp[N - i][b]) % MOD;
    }
    long long expectedValue = (totalPaths - blockedPaths + MOD) % MOD;
    printf("%lld\n", expectedValue);
    return 0;
}

